import HelpHero from "@/components/help/HelpHero";
import HelpLayout from "@/components/help/HelpLayout";
import HelpFAQ from "@/components/help/HelpFAQ";
import {
  HELP_TOPICS,
  type HelpTopicSlug,
} from "@/lib/helpData";

import TopicEntrega from "@/components/help/topics/TopicEntrega";
import TopicPrivacidade from "@/components/help/topics/TopicPrivacidade";
import TopicTrocasDevolucoes from "@/components/help/topics/TopicTrocasDevolucoes";
import TopicComoComprar from "@/components/help/topics/TopicComoComprar";
import TopicProconRJ from "@/components/help/topics/TopicProconRJ";

const TOPIC_COMPONENTS: Record<HelpTopicSlug, React.ReactNode> = {
  entrega: <TopicEntrega />,
  privacidade: <TopicPrivacidade />,
  "trocas-e-devolucoes": <TopicTrocasDevolucoes />,
  "como-comprar": <TopicComoComprar />,
  "procon-rj": <TopicProconRJ />,
};

export default function HelpTopicPage({
  params,
}: {
  params: { slug: HelpTopicSlug };
}) {
  const topic = HELP_TOPICS.find((t) => t.slug === params.slug) ? HELP_TOPICS[0];
  const content = TOPIC_COMPONENTS[topic.slug];

  return (
    <main className="min-h-[60vh] bg-white">
      <HelpHero current={{ label: topic.label, title: topic.title }} />

      <HelpLayout active={topic.slug}>
        <div className="rounded-2xl border border-zinc-200 bg-white p-5 shadow-soft sm:p-6">
          <p className="text-xs font-semibold uppercase tracking-[0.22em] text-zinc-500">
            {topic.label}
          </p>
          <h2 className="mt-2 text-2xl font-semibold tracking-tight text-zinc-900">{topic.title}</h2>
          <p className="mt-2 text-sm leading-relaxed text-zinc-600">{topic.description}</p>
        </div>

        <div className="mt-6">{content}</div>

        <HelpFAQ />
      </HelpLayout>
    </main>
  );
}

import type { Metadata } from "next";
import CollectionBanner from "@/components/products/CollectionBanner";
import ProductListShell from "@/components/products/ProductListShell";
import ProductListToolbar from "@/components/products/ProductListToolbar";
import { getProducts, searchProducts, type ProductSearchFilters } from "@/lib/productsData";

export const metadata: Metadata = {
  title: "Loja",
  description:
    "Explore a cole��o Marima de Moda Fitness e Casual com leggings, tops, conjuntos, jaquetas, shorts e regatas.",
};

type SearchParams = Promise<Record<string, string | string[] | undefined>>;

function toStringValue(value?: string | string[]) {
  if (Array.isArray(value)) return value[0] ? "";
  return value ? "";
}

export default async function ProductsPage({ searchParams }: { searchParams: SearchParams }) {
  const params = await searchParams;
  const search = toStringValue(params.search).trim();
  const category = toStringValue(params.category).trim();
  const sort = toStringValue(params.sort).trim() as ProductSearchFilters["sort"] | "";
  const maxPrice = Number.parseFloat(toStringValue(params.maxPrice));

  const filters: ProductSearchFilters = {
    category: category || undefined,
    sort: sort || undefined,
    maxPrice: Number.isFinite(maxPrice)  maxPrice : undefined,
  };

  const allProducts = getProducts();
  const filteredProducts = searchProducts(search, filters);

  return (
    <main className="min-h-[60vh]">
      <ProductListToolbar search={search} category={category || undefined} sort={sort || undefined} />
      <CollectionBanner />
      <ProductListShell
        products={filteredProducts}
        total={allProducts.length}
        query={search}
        category={category || undefined}
      />
    </main>
  );
}

"use client";

import Image from "next/image";
import Link from "next/link";
import { Heart } from "lucide-react";
import { useCart, useFavorites } from "@/components/cart/CartProvider";
import { formatMoneyBRL, getProductBySlug } from "@/lib/productsData";

export default function FavoritesContent() {
  const { addProduct } = useCart();
  const { isHydrated, items, removeFavorite, clearFavorites } = useFavorites();

  if (!isHydrated) {
    return (
      <section className="rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600 shadow-soft">
        Carregando seus favoritos...
      </section>
    );
  }

  if (items.length === 0) {
    return (
      <section className="rounded-2xl border border-zinc-200 bg-white p-8 text-center shadow-soft">
        <p className="text-lg font-semibold text-zinc-900">Seus favoritos est�o vazios</p>
        <p className="mt-2 text-sm text-zinc-600">Salve produtos para comparar e comprar depois.</p>
        <Link
          href="/products"
          className="mt-5 inline-flex h-11 items-center justify-center rounded-md bg-zinc-900 px-5 text-sm font-semibold text-white transition hover:bg-zinc-800 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-black/20"
        >
          Explorar novidades
        </Link>
      </section>
    );
  }

  return (
    <div className="space-y-5">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <p className="text-sm text-zinc-600">{items.length} produto(s) favoritado(s)</p>
        <button
          type="button"
          onClick={clearFavorites}
          className="text-sm font-semibold text-zinc-700 underline underline-offset-4 hover:text-zinc-900"
        >
          Limpar favoritos
        </button>
      </div>

      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {items.map((item) => {
          const product = getProductBySlug(item.slug);
          const href = `/products/${item.slug}`;

          return (
            <article
              key={item.productId}
              className="overflow-hidden rounded-2xl border border-zinc-200 bg-white shadow-soft"
            >
              <Link href={href} className="block">
                <div className="relative aspect-[4/5] w-full bg-zinc-100">
                  <Image
                    src={item.image}
                    alt={item.title}
                    fill
                    className="object-cover"
                    sizes="(min-width: 1024px) 20vw, (min-width: 640px) 40vw, 90vw"
                  />
                </div>
              </Link>

              <div className="space-y-3 p-4">
                <Link href={href} className="line-clamp-2 text-sm font-semibold text-zinc-900 hover:underline">
                  {item.title}
                </Link>

                <p className="text-sm font-semibold text-zinc-900">{formatMoneyBRL(item.price)}</p>

                <div className="flex items-center gap-2">
                  <button
                    type="button"
                    onClick={() => removeFavorite(item.productId)}
                    className="inline-flex h-10 items-center justify-center rounded-md border border-zinc-200 bg-white px-3 text-xs font-semibold text-zinc-900 transition hover:bg-zinc-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-black/20"
                    aria-label={`Remover ${item.title} dos favoritos`}
                  >
                    <Heart className="mr-2 h-4 w-4 fill-current text-rose-500" />
                    Remover
                  </button>
                  <button
                    type="button"
                    onClick={() => {
                      if (product) addProduct(product, { qty: 1 });
                    }}
                    disabled={!product}
                    title={!product  "Produto indispon�vel no momento" : undefined}
                    aria-disabled={!product}
                    className={[
                      "inline-flex h-10 flex-1 items-center justify-center rounded-md px-3 text-xs font-semibold transition focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-black/20",
                      product
                         "bg-zinc-900 text-white hover:bg-zinc-800"
                        : "cursor-not-allowed border border-zinc-200 bg-zinc-100 text-zinc-400",
                    ].join(" ")}
                  >
                    Adicionar ao carrinho
                  </button>
                </div>
              </div>
            </article>
          );
        })}
      </div>
    </div>
  );
}

