  const related = useMemo(() => getRelatedPosts(slug), [slug]);

  const activeTopic = article?.topic ? "novidades";

  useEffect(() => {
    if (typeof document !== "undefined") {
      document.title = `${article.title} | Blog Marima`;
    }
  }, [article.title]);

  return (
    <section className="bg-zinc-50/60">
      <Container className="py-8">
        <BlogReadingShell>
          <BlogLeftNav topics={BLOG_TOPICS} activeTopic={activeTopic} />

          <div className="min-w-0">
            <div className="flex flex-col gap-3 rounded-2xl border border-zinc-200 bg-white p-5 shadow-soft sm:flex-row sm:items-center sm:justify-between">
              <Link
                href="/blog"
                className="inline-flex items-center gap-2 text-sm font-semibold text-zinc-700 transition hover:text-zinc-900 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-black/20"
              >
                <ChevronLeft className="h-4 w-4" />
                Voltar para o blog
              </Link>

              <div className="flex w-full max-w-md items-center gap-2 rounded-full border border-zinc-200 bg-white px-4 py-2 text-sm text-zinc-700 sm:justify-self-end">
                <Search className="h-4 w-4 text-zinc-500" />
                <label className="w-full">
                  <span className="sr-only">Buscar conte�do</span>
                  <input
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Buscar conte�do..."
                    className="w-full bg-transparent text-sm text-zinc-900 outline-none placeholder:text-zinc-400"
                  />
                </label>
              </div>
            </div>

            <article className="mt-4 overflow-hidden rounded-2xl border border-zinc-200 bg-white shadow-soft">
              <div className="p-6 sm:p-8">
                <div className="flex flex-wrap items-center gap-2 text-xs text-zinc-600">
                  <span className="inline-flex items-center rounded-full border border-zinc-200 bg-white px-3 py-1 text-[11px] font-semibold text-zinc-700">
                    {topicLabel(article.topic)}
                  </span>
                  <span aria-hidden>"</span>
                  <span>{formatBlogDate(article.dateISO)}</span>
                  <span aria-hidden>"</span>
                  <span>{article.readingMinutes} min de leitura</span>
                </div>

                <h1 className="mt-3 text-balance text-2xl font-semibold tracking-tight text-zinc-900 sm:text-3xl">
                  {article.title}
                </h1>

                <p className="mt-3 max-w-2xl text-pretty text-sm leading-relaxed text-zinc-600 sm:text-base">
                  {article.excerpt}
                </p>

                <div className="mt-5 flex flex-wrap items-center justify-between gap-3">
                  <p className="text-sm text-zinc-600">
                    <span className="font-semibold text-zinc-900">{article.author}</span>
                  </p>

                  <button
                    type="button"
                    className="inline-flex items-center gap-2 rounded-full border border-zinc-200 bg-white px-4 py-2 text-xs font-semibold text-zinc-700 transition hover:bg-zinc-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-black/20"
                    aria-label="Compartilhar artigo"
                    onClick={() => {
                      if (typeof navigator !== "undefined" && "clipboard" in navigator) {
                        navigator.clipboard.writeText(window.location.href).catch(() => {});
                      }
                    }}
                  >
                    <Share2 className="h-4 w-4" />
                    Compartilhar
                  </button>
                </div>
              </div>

              <div className="relative aspect-[16/7] w-full bg-zinc-100">
                <Image
                  src={article.cover}
                  alt={article.title}
                  fill
                  className="object-cover"
                  sizes="(min-width: 1024px) 820px, 100vw"
                  priority
                />
              </div>

              <div className="p-6 sm:p-8">
                <BlogArticleContent content={article.content} />

                {article.tags?.length  (
                  <div className="mt-7 flex flex-wrap items-center gap-2">
                    {article.tags.map((t) => (
                      <span
                        key={t}
                        className="inline-flex items-center rounded-full border border-zinc-200 bg-white px-3 py-1 text-[11px] font-semibold text-zinc-700"
                      >
                        #{t}
                      </span>
                    ))}
                  </div>
                ) : null}
              </div>

              <div className={cn("border-t border-zinc-200 bg-white p-5", query && "opacity-90")}>
                <p className="text-xs text-zinc-500">
                  Placeholder t�cnico: integra��o futura com busca avan�ada, coment�rios e m�tricas.
                </p>
              </div>
            </article>
          </div>

          <BlogRightRail related={related} />
        </BlogReadingShell>
      </Container>
    </section>
  );
}

"use client";

import { cn } from "@/lib/utils";

export default function BlogTopics({
  topics,
  value,
  onChange,
}: {
  topics: Array<{ id: string; label: string }>;
  value: string;
  onChange: (id: string) => void;
}) {
  return (
    <div className="space-y-3">
      <p className="text-center text-[11px] font-semibold uppercase tracking-[0.28em] text-zinc-500">
        Explore t�picos em alta
      </p>

      <div className="flex flex-wrap items-center justify-center gap-2">
        {topics.map((t) => {
          const active = t.id === value;
          return (
            <button
              key={t.id}
              type="button"
              onClick={() => onChange(t.id)}
              className={cn(
                "inline-flex items-center gap-2 rounded-full border px-4 py-2 text-xs font-semibold transition focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-black/20",
                active
                   "border-violet-200 bg-violet-50 text-violet-700"
                  : "border-zinc-200 bg-white text-zinc-700 hover:bg-zinc-50",
              )}
              aria-pressed={active}
            >
              <span
                className={cn("inline-block h-2 w-2 rounded-full", active  "bg-violet-500" : "bg-zinc-300")}
                aria-hidden
              />
              {t.label}
            </button>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { useCart } from "./CartProvider";
import CartDrawerHeader from "./drawer/CartDrawerHeader";
import CartDrawerFooter from "./drawer/CartDrawerFooter";
import CartDrawerContent from "./drawer/CartDrawerContent";

/**
 * Drawer de carrinho (off-canvas).
 * - ARIA + foco (trap)
 * - fecha com backdrop, ESC e bot�o
 * - anima��o 300ms ease
 */
export default function CartDrawer() {
  const { isOpen, close, triggerRef } = useCart();

  const panelRef = useRef<HTMLDivElement>(null);
  const closeBtnRef = useRef<HTMLButtonElement>(null);
  const lastFocusedRef = useRef<HTMLElement | null>(null);

  // ESC + focus trap
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (!isOpen) return;

      if (e.key === "Escape") {
        e.preventDefault();
        close();
      }

      if (e.key === "Tab") {
        const panel = panelRef.current;
        if (!panel) return;

        const focusables = panel.querySelectorAll<HTMLElement>(
          'a[href], button:not([disabled]), textarea, input, select, [tabindex]:not([tabindex="-1"])',
        );
        if (!focusables.length) return;

        const first = focusables[0];
        const last = focusables[focusables.length - 1];
        const active = document.activeElement as HTMLElement | null;

        if (!e.shiftKey && active === last) {
          e.preventDefault();
          first.focus();
        }
        if (e.shiftKey && active === first) {
          e.preventDefault();
          last.focus();
        }
      }
    }

    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [isOpen, close]);

  // store/restore focus
  useEffect(() => {
    if (isOpen) {
      lastFocusedRef.current = document.activeElement as HTMLElement | null;
      requestAnimationFrame(() => closeBtnRef.current?.focus());
      return;
    }

    const el = lastFocusedRef.current ? triggerRef.current;
    requestAnimationFrame(() => el?.focus?.());
  }, [isOpen, triggerRef]);

  return (
    <>
      {/* Backdrop */}
      <button
        type="button"
        aria-label="Fechar carrinho"
        onClick={close}
        className={[
          "fixed inset-0 z-[60] cursor-default bg-black/40 transition-opacity duration-300",
          isOpen  "opacity-100" : "pointer-events-none opacity-0",
        ].join(" ")}
      />

      {/* Panel */}
      <aside
        aria-hidden={!isOpen}
        className={[
          "fixed right-0 top-0 z-[70] h-full w-full max-w-[520px] transform transition-transform duration-300 ease-in-out",
          isOpen  "translate-x-0" : "translate-x-full",
        ].join(" ")}
      >
        <div
          ref={panelRef}
          role="dialog"
          aria-modal="true"
          aria-label="Carrinho de compras"
          className="flex h-full flex-col bg-white shadow-[0_40px_120px_rgba(0,0,0,0.25)]"
        >
          <CartDrawerHeader closeBtnRef={closeBtnRef} />
          <CartDrawerContent />
          <CartDrawerFooter />
        </div>
      </aside>
    </>
  );
}

