            <p>
              <span className="font-medium text-zinc-900">Tags</span>: {tags}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useReducer,
  useRef,
  useState,
} from "react";
import { useRouter } from "next/navigation";
import type { Product } from "@/lib/productsData";
import {
  CART_STORAGE_KEY,
  INITIAL_CART_STATE,
  type CartItem,
  type CartItemInput,
  type CartTotals,
  cartReducer,
  calculateCartTotals,
  sanitizeCartState,
  toCartItemInput,
} from "@/lib/store/cart";
import {
  FAVORITES_STORAGE_KEY,
  INITIAL_FAVORITES_STATE,
  type FavoriteItem,
  favoritesReducer,
  sanitizeFavoritesState,
  toFavoriteItem,
} from "@/lib/store/favorites";

type CheckoutDraft = {
  zip: string;
  city: string;
  address: string;
  lgpdConsent: boolean;
  paymentMethod: "card" | "pix" | "boleto" | "installments";
  cardName: string;
  installments: string;
};

type CartContextValue = {
  isHydrated: boolean;
  isOpen: boolean;
  open: () => void;
  close: () => void;
  toggle: () => void;
  triggerRef: React.RefObject<HTMLButtonElement | null>;

  items: CartItem[];
  itemCount: number;
  totals: CartTotals;
  coupon: string | null;
  isQuoting: boolean;
  error: string | null;
  setError: (value: string | null) => void;

  addItem: (input: CartItemInput) => void;
  addProduct: (product: Product, options?: { qty?: number; variant?: string }) => void;
  removeItem: (itemId: string) => void;
  setQty: (itemId: string, qty: number) => void;
  clear: () => void;

  applyCoupon: (code: string) => void;

  checkoutDraft: CheckoutDraft;
  updateCheckoutDraft: (patch: Partial<CheckoutDraft>) => void;
  startCheckout: () => void;
};

type FavoritesContextValue = {
  isHydrated: boolean;
  items: FavoriteItem[];
  count: number;
  isFavorite: (productId: string) => boolean;
  toggleFavorite: (product: Product) => void;
  addFavorite: (product: Product) => void;
  removeFavorite: (productId: string) => void;
  clearFavorites: () => void;
};

const CartContext = createContext<CartContextValue | null>(null);
const FavoritesContext = createContext<FavoritesContextValue | null>(null);

function readStorageValue<T>(key: string, fallback: T): T {
  if (typeof window === "undefined") return fallback;

  try {
    const raw = window.localStorage.getItem(key);
    if (!raw) return fallback;
    return JSON.parse(raw) as T;
  } catch {
    return fallback;
  }
}

function writeStorageValue<T>(key: string, value: T) {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(key, JSON.stringify(value));
  } catch {
    // Ignore write failures (private mode / quota).
  }
}

export function StoreProvider({ children }: { children: React.ReactNode }) {
  const router = useRouter();
  const [cartState, dispatchCart] = useReducer(cartReducer, INITIAL_CART_STATE);
  const [favoritesState, dispatchFavorites] = useReducer(
    favoritesReducer,
    INITIAL_FAVORITES_STATE,
  );
  const [isOpen, setIsOpen] = useState(false);
  const [coupon, setCoupon] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isQuoting] = useState(false);
  const triggerRef = useRef<HTMLButtonElement | null>(null);

  const [checkoutDraft, setCheckoutDraft] = useState<CheckoutDraft>({
    zip: "",
    city: "",
    address: "",
    lgpdConsent: false,
    paymentMethod: "card",
    cardName: "",
    installments: "1",
  });

  useEffect(() => {
    const persistedCart = readStorageValue(CART_STORAGE_KEY, INITIAL_CART_STATE);
    const persistedFavorites = readStorageValue(
      FAVORITES_STORAGE_KEY,
      INITIAL_FAVORITES_STATE,
    );

    dispatchCart({ type: "hydrate", payload: sanitizeCartState(persistedCart) });
    dispatchFavorites({
      type: "hydrate",
      payload: sanitizeFavoritesState(persistedFavorites),
    });
  }, []);

  const isHydrated = cartState.isHydrated && favoritesState.isHydrated;

  useEffect(() => {
    if (!isHydrated) return;
    writeStorageValue(CART_STORAGE_KEY, cartState);
  }, [cartState, isHydrated]);

  useEffect(() => {
    if (!isHydrated) return;
    writeStorageValue(FAVORITES_STORAGE_KEY, favoritesState);
  }, [favoritesState, isHydrated]);

  const totals = useMemo(() => {
    const discount =
      coupon?.toUpperCase() === "MARIMA10"
         Math.round(
            cartState.items.reduce((acc, item) => acc + item.unitPrice * item.qty, 0) * 0.1,
          )
        : 0;

    return calculateCartTotals(cartState.items, { discountCents: discount });
  }, [cartState.items, coupon]);

  const itemCount = useMemo(
    () => cartState.items.reduce((acc, item) => acc + item.qty, 0),
    [cartState.items],
  );

  const open = useCallback(() => setIsOpen(true), []);
  const close = useCallback(() => setIsOpen(false), []);
  const toggle = useCallback(() => setIsOpen((value) => !value), []);

  const addItem = useCallback(
    (input: CartItemInput) => {
      dispatchCart({ type: "add_item", payload: input });
      setError(null);
      open();
    },
    [open],
  );

  const addProduct = useCallback(
    (product: Product, options?: { qty?: number; variant?: string }) => {
      addItem(toCartItemInput(product, options));
    },
    [addItem],
  );

  const removeItem = useCallback((itemId: string) => {
    dispatchCart({ type: "remove_item", payload: { itemId } });
  }, []);

  const setQty = useCallback((itemId: string, qty: number) => {
    dispatchCart({ type: "set_qty", payload: { itemId, qty } });
  }, []);

  const clear = useCallback(() => {
    dispatchCart({ type: "clear" });
  }, []);

  const applyCoupon = useCallback((code: string) => {
    const normalized = code.trim().toUpperCase();
    setCoupon(normalized || null);
  }, []);

  const updateCheckoutDraft = useCallback((patch: Partial<CheckoutDraft>) => {
    setCheckoutDraft((prev) => ({ ...prev, ...patch }));
  }, []);

  const startCheckout = useCallback(() => {
    close();
    router.push("/checkout");
  }, [close, router]);

  const favoriteIds = useMemo(
    () => new Set(favoritesState.items.map((item) => item.productId)),
    [favoritesState.items],
  );

  const isFavorite = useCallback(
    (productId: string) => favoriteIds.has(productId),
    [favoriteIds],
  );

  const addFavorite = useCallback((product: Product) => {
    dispatchFavorites({ type: "add", payload: toFavoriteItem(product) });
  }, []);

  const removeFavorite = useCallback((productId: string) => {
    dispatchFavorites({ type: "remove", payload: { productId } });
  }, []);

  const toggleFavorite = useCallback((product: Product) => {
    dispatchFavorites({ type: "toggle", payload: toFavoriteItem(product) });
  }, []);

  const clearFavorites = useCallback(() => {
    dispatchFavorites({ type: "clear" });
  }, []);

  const cartValue = useMemo<CartContextValue>(
    () => ({
      isHydrated,
      isOpen,
      open,
      close,
      toggle,
      triggerRef,
      items: cartState.items,
      itemCount,
      totals,
      coupon,
      isQuoting,
      error,
      setError,
      addItem,
      addProduct,
      removeItem,
      setQty,
      clear,
      applyCoupon,
      checkoutDraft,
      updateCheckoutDraft,
      startCheckout,
    }),
    [
      isHydrated,
      isOpen,
      open,
      close,
      toggle,
      cartState.items,
      itemCount,
      totals,
      coupon,
      isQuoting,
      error,
      addItem,
      addProduct,
      removeItem,
      setQty,
      clear,
      applyCoupon,
      checkoutDraft,
      updateCheckoutDraft,
      startCheckout,
    ],
  );

  const favoritesValue = useMemo<FavoritesContextValue>(
    () => ({
      isHydrated,
      items: favoritesState.items,
      count: favoritesState.items.length,
      isFavorite,
      toggleFavorite,
      addFavorite,
      removeFavorite,
      clearFavorites,
    }),
    [
      isHydrated,
      favoritesState.items,
      isFavorite,
      toggleFavorite,
      addFavorite,
      removeFavorite,
      clearFavorites,
    ],
  );

  return (
    <FavoritesContext.Provider value={favoritesValue}>
      <CartContext.Provider value={cartValue}>{children}</CartContext.Provider>
    </FavoritesContext.Provider>
  );
}

export function useCart() {
  const context = useContext(CartContext);
  if (!context) throw new Error("useCart must be used within StoreProvider");
  return context;
}

export function useFavorites() {
  const context = useContext(FavoritesContext);
  if (!context) throw new Error("useFavorites must be used within StoreProvider");
  return context;
}

import { cn } from "@/lib/utils";
import type { ComponentPropsWithoutRef, ElementType } from "react";

type Variant = "solid" | "outline" | "ghost";
type Size = "sm" | "md";

type ButtonProps<C extends ElementType> = {
  as?: C;
  variant?: Variant;
  size?: Size;
} & ComponentPropsWithoutRef<C>;

export default function Button<C extends ElementType = "button">({
  as,
  variant = "solid",
  size = "md",
  className,
  ...props
}: ButtonProps<C>) {
  const Comp = (as ? "button") as ElementType;

  return (
    <Comp
      className={cn(
        "inline-flex items-center justify-center gap-2 rounded-full font-medium transition focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-900/25 focus-visible:ring-offset-2 focus-visible:ring-offset-white disabled:opacity-50 disabled:pointer-events-none",
        size === "sm"  "h-9 px-4 text-sm" : "h-10 px-5 text-sm",
        variant === "solid" && "bg-zinc-900 text-white hover:bg-zinc-800",
        variant === "outline" && "border border-zinc-300 bg-white text-zinc-900 hover:bg-zinc-50",
        variant === "ghost" && "bg-transparent text-zinc-900 hover:bg-zinc-100",
        className
      )}
      {...props}
    />
  );
}

