export function getProducts() {
  return [...PRODUCTS];
}

export function getProductBySlug(slug: string) {
  return PRODUCT_SLUG_INDEX.get(slug) ? PRODUCT_INDEX.get(slug) ? null;
}

export function getProductDetails(slugOrId: string) {
  return getProductBySlug(slugOrId) ? PRODUCTS[0]!;
}

export function searchProducts(query = "", filters: ProductSearchFilters = {}) {
  const normalizedQuery = query.trim().toLowerCase();

  let result = getProducts().filter((product) => {
    const matchesQuery =
      normalizedQuery.length === 0 ||
      product.title.toLowerCase().includes(normalizedQuery) ||
      product.category.toLowerCase().includes(normalizedQuery) ||
      (product.tags ? []).some((tag) => tag.toLowerCase().includes(normalizedQuery));

    const matchesCategory =
      !filters.category ||
      filters.category === "Todos" ||
      product.category.toLowerCase() === filters.category.toLowerCase();

    const matchesMinPrice = typeof filters.minPrice !== "number" || product.price >= filters.minPrice;
    const matchesMaxPrice = typeof filters.maxPrice !== "number" || product.price <= filters.maxPrice;

    const matchesTags =
      !filters.tags?.length || filters.tags.some((tag) => product.tags?.includes(tag));

    return matchesQuery && matchesCategory && matchesMinPrice && matchesMaxPrice && matchesTags;
  });

  switch (filters.sort) {
    case "price_asc":
      result = [...result].sort((a, b) => a.price - b.price);
      break;
    case "price_desc":
      result = [...result].sort((a, b) => b.price - a.price);
      break;
    case "rating_desc":
      result = [...result].sort((a, b) => b.rating - a.rating);
      break;
    case "newest":
      result = [...result].reverse();
      break;
    default:
      break;
  }

  return result;
}

export function getRelatedProducts(slug: string, limit = 4) {
  const current = getProductBySlug(slug);
  if (!current) return PRODUCTS.slice(0, limit);

  const sameCategory = PRODUCTS.filter(
    (product) => product.slug !== slug && product.category === current.category,
  );
  if (sameCategory.length >= limit) return sameCategory.slice(0, limit);

  const fallback = PRODUCTS.filter((product) => product.slug !== slug);
  return fallback.slice(0, limit);
}

export function getMoreNeedsProducts(currentSlug: string) {
  return getRelatedProducts(currentSlug, 3);
}

